	public class GetEntityTokenRequest : PlayFabRequestCommon
	{
		public EntityKey Entity;
	}
	[Serializable]
	public class GetEntityTokenResponse : PlayFabResultCommon
	{
		public EntityKey Entity;

		public string EntityToken;

		public DateTime? TokenExpiration;
	}
